export const extractThumbnailFromUrl = (url) => {
  if (!url) return null;

  try {
    const urlObj = new URL(url);
    const hostname = urlObj.hostname.toLowerCase();

    // YouTube
    if (hostname.includes('youtube.com') || hostname.includes('youtu.be')) {
      const videoId = extractYouTubeVideoId(url);
      if (videoId) {
        return `https://img.youtube.com/vi/${videoId}/hqdefault.jpg`;
      }
    }

    // Instagram
    if (hostname.includes('instagram.com')) {
      // Instagram doesn't provide direct thumbnail URLs via API
      // We'll use a placeholder or try to extract from the URL
      return null;
    }

    // Facebook
    if (hostname.includes('facebook.com')) {
      // Facebook doesn't provide direct thumbnail URLs
      return null;
    }

    // TikTok
    if (hostname.includes('tiktok.com')) {
      // TikTok doesn't provide direct thumbnail URLs
      return null;
    }

    // Vimeo
    if (hostname.includes('vimeo.com')) {
      const videoId = extractVimeoVideoId(url);
      if (videoId) {
        return `https://vumbnail.com/${videoId}.jpg`;
      }
    }

    return null;
  } catch (error) {
    console.error('Error extracting thumbnail:', error);
    return null;
  }
};

const extractYouTubeVideoId = (url) => {
  const patterns = [
    /(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&\n?#]+)/,
    /youtube\.com\/embed\/([^&\n?#]+)/,
    /youtube\.com\/v\/([^&\n?#]+)/,
  ];

  for (const pattern of patterns) {
    const match = url.match(pattern);
    if (match) {
      return match[1];
    }
  }

  return null;
};

const extractVimeoVideoId = (url) => {
  const pattern = /vimeo\.com\/(\d+)/;
  const match = url.match(pattern);
  return match ? match[1] : null;
};

export const getFallbackThumbnail = (platform) => {
  // Use data URIs instead of external placeholder URLs to avoid network errors
  const fallbackThumbnails = {
    youtube: 'data:image/svg+xml;base64,',
    instagram: 'data:image/svg+xml;base64,',
    facebook: 'data:image/svg+xml;base64,',
    tiktok: 'data:image/svg+xml;base64,',
    vimeo: 'data:image/svg+xml;base64,',
    custom: 'data:image/svg+xml;base64,'
  };

  if (!platform || typeof platform !== 'string') {
    return fallbackThumbnails.custom;
  }

  return fallbackThumbnails[platform.toLowerCase()] || fallbackThumbnails.custom;
}; 